patch:
diff --git a/llvm/lib/Transforms/Vectorize/VPlanUnroll.cpp b/llvm/lib/Transforms/Vectorize/VPlanUnroll.cpp
index 62fd83a5e092..e5af2d586831 100644
--- a/llvm/lib/Transforms/Vectorize/VPlanUnroll.cpp
+++ b/llvm/lib/Transforms/Vectorize/VPlanUnroll.cpp
@@ -529,6 +529,9 @@ void VPlanTransforms::replicateByVF(VPlan &Plan, ElementCount VF) {
   // The removal of current recipes being replaced by new ones needs to be
   // delayed after Def2LaneDefs is no longer in use.
   SmallVector<VPRecipeBase *> ToRemove;
+  // Type analysis used to decide whether to build a vector or struct-of-vectors
+  // when redirecting remaining vector users.
+  VPTypeAnalysis TypeInfo(Plan);
   for (VPBasicBlock *VPBB : VPBBsToUnroll) {
     for (VPRecipeBase &R : make_early_inc_range(*VPBB)) {
       auto *RepR = dyn_cast<VPReplicateRecipe>(&R);
@@ -577,6 +580,29 @@ void VPlanTransforms::replicateByVF(VPlan &Plan, ElementCount VF) {
         for (VPValue *LaneDef : drop_begin(LaneDefs))
           VPI->addOperand(LaneDef);
       }
+
+      // If there are still remaining users that expect a vector (e.g. widen
+      // recipes), build a vector from the lane definitions and redirect those
+      // users to it. Keep VPReplicateRecipe users intact, as they will be
+      // scalarized later using Def2LaneDefs.
+      if (RepR->getNumUsers() != 0) {
+        Type *ScalarTy = TypeInfo.inferScalarType(RepR);
+        unsigned Opcode = ScalarTy->isStructTy() ? VPInstruction::BuildStructVector
+                                                 : VPInstruction::BuildVector;
+        // Create with a single operand first to satisfy constructor checks, then
+        // append the remaining lane defs.
+        auto *BV = new VPInstruction(Opcode, {LaneDefs[0]});
+        BV->insertAfter(RepR);
+        for (VPValue *LaneDef : drop_begin(LaneDefs))
+          BV->addOperand(LaneDef);
+        RepR->replaceUsesWithIf(BV, [](VPUser &U, unsigned) {
+          // Redirect all remaining users to the Build(Vector) we just created.
+          // VPReplicateRecipe users will look through buildvector in cloneForLane.
+          (void)U;
+          return true;
+        });
+      }
+
       ToRemove.push_back(RepR);
     }
   }

